const Q_GOVERNMENT_2011=[{"id": "objective>Government>2011>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">History</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Literature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C.R.K</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject is indicated in the id of the question. The id 'objective>Government>2011>1' shows that the subject is Government.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POLITICAL PROCESSES: POLITICAL SOCIALIZATION, POLITICAL PARTICIPATION AND POLITICAL CULTURE"}, {"id": "objective>Government>2011>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The development of attitudes and beliefs about a political system is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political participation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political orientation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political emancipation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political socialization</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Political orientation refers to the development of attitudes and beliefs about a political system. It is the process by which individuals acquire their political beliefs and attitudes, often through socialization processes such as family, school, peers, media, and significant life events. The other options do not accurately describe this process. Political participation refers to the activities of the public in the political process, such as voting or campaigning. Political emancipation refers to the process of gaining political rights or freedoms. Political socialization is the process by which people learn about and develop their political beliefs and attitudes, but it is a broader concept than political orientation, which specifically refers to the attitudes and beliefs about a political system.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POLITICAL PROCESSES: POLITICAL SOCIALIZATION, POLITICAL PARTICIPATION AND POLITICAL CULTURE"}, {"id": "objective>Government>2011>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Political behavior is governed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political culture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political socialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political ideology</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Political behavior is governed by political culture. Political culture refers to the attitudes, beliefs, and values which underpin the operation of a particular political system. These have been seen as including aspects like levels of civic engagement and trust in government, attitudes towards the rights and responsibilities of citizens, and beliefs about how political change should be brought about.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POLITICAL SOCIALIZATION, POLITICAL PARTICIPATION AND POLITICAL CULTURE"}, {"id": "objective>Government>2011>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a nation, sovereignty is vested on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electorate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">state</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a nation, sovereignty is vested on the state. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. In international law, sovereignty is the exercise of power by a state.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>2011>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a feature of democracy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Power vested in minority parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Popular consultation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interdependence of state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">State responsibilities to society</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A feature of democracy is popular consultation. This means that in a democratic system, decisions are made based on the consultation and agreement of the majority of the people. This is in contrast to power being vested in minority parties, which is not a feature of democracy. Interdependence of state and state responsibilities to society are also not specific features of democracy.</div>", "topic": "FORMS OF GOVERNMENT : DEMOCRACY FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2011>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Private ownership of the means of production is central to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capitalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fascism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feudalism</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Private ownership of the means of production is central to capitalism. In a capitalist system, individuals and businesses have the right to own and control the means of production, which includes things like factories, machinery, and land. This is in contrast to communism, where the means of production are owned and controlled by the state. Fascism and feudalism also do not center around private ownership of the means of production.</div>", "topic": "POLITICAL IDEOLOGIES : CAPITALISM"}, {"id": "objective>Government>2011>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A system based on hierarchies of land ownership is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">communism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fascism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feudalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">totalitarianism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Feudalism is a system based on hierarchies of land ownership. In this system, the king would grant land to his most important noblemen and bishops. These grants of land were called fiefs. In return, the noblemen and bishops would provide services, like soldiers for the king's army, to the king. This system was based on rights and obligations. In theory, the king owned all the land in the kingdom.</div>", "topic": "POLITICAL IDEOLOGIES : FEUDALISM"}, {"id": "objective>Government>2011>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following performs quasi legislative functions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Civil Service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Executive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Judiciary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Traditional Institutions</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Judiciary performs quasi legislative functions. Quasi-legislative functions refer to the actions or decisions made by an administrative or executive body (like the Judiciary) that have the force and effect of law. These functions are typically associated with the rule-making process, where the Judiciary can make rules that have the force of law. This is different from the traditional legislative process, where laws are created by a legislative body like a parliament or congress.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2011>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major weakness of confederation is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lack of local independence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of common currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over-concentration of authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tendency towards secession</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A confederation is a system of government where power is located with the independent states and a little power is given to the central government. This system tends to have a weakness towards secession because the states have the power to break away or secede from the confederation. Therefore, the correct answer is 'tendency towards secession'.</div>", "topic": "STRUCTURES OF GOVERNANCE : CONFEDERAL FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS"}, {"id": "objective>Government>2011>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Members of a parliament are required to report the proceedings of the house to their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">traditional rulers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constituencies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">local government chairman</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Members of a parliament are representatives of their constituencies. They are required to report back to their constituencies about the proceedings of the house. This is to ensure transparency and accountability in their representation. Therefore, the correct answer is 'constituencies'.</div>", "topic": "INSTITUTIONS OF GOVERNMENT IN THE POST-INDEPENDENCE NIGERIA : THE LEGISLATIVE – STRUCTURE, FUNCTIONS AND WORKING."}, {"id": "objective>Government>2011>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following countries is a unitary state?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">United States of America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">India</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A unitary state is a state governed as a single entity in which the central government is ultimately supreme. The central government may create (or abolish) administrative divisions (sub-national units). Such units exercise only the powers that the central government chooses to delegate. Ghana is a unitary state. The United States of America, Nigeria, and India are federal states, where there is division of power between the central government and the states or provinces.</div>", "topic": "STRUCTURES OF GOVERNANCE : UNITARY FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS"}, {"id": "objective>Government>2011>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ending a session of parliament by royal proclamation means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adjournment of parliament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolution of parliament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expiration of parliament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prorogation of parliament</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prorogation is the action of discontinuing a session of a parliament or other legislative assembly without dissolving it. It is a formal mechanism that ends a parliamentary session. When the parliament is prorogued, no business can be conducted. In other words, it is the end of a parliamentary session. It is different from adjournment (a short break in proceedings), dissolution (end of the life of a parliament leading to elections), and expiration (end of the maximum life of a parliament).</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2011>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A main feature of the parliamentary system is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electoral commissioners leave at the end of their tenure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the executive is appointed by the legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the executive consists of all party members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">judges are drawn from the ruling party</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a parliamentary system, the executive is appointed by the legislature. This is because the executive branch derives its democratic legitimacy from the legislature and is also held accountable to it. The executive includes individuals who are members of the legislature, but the executive does not consist of all party members. The other options are incorrect because they do not accurately describe features of a parliamentary system.</div>", "topic": "SYSTEMS OF GOVERNANCE : PARLIAMENTARY SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>2011>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a socialist economy, private accumulation wealth is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">limited</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prohibited</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regulated</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a socialist economy, private accumulation of wealth is limited. This is because socialism advocates for wealth and income equality. Therefore, the accumulation of wealth is controlled to prevent the creation of wealth disparities. The other options are incorrect because they do not accurately describe the approach to wealth accumulation in a socialist economy.</div>", "topic": "POLITICAL IDEOLOGIES : SOCIALISM"}, {"id": "objective>Government>2011>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The earliest classification of constitutions was the work of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K.C Wheare</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plato</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aristotle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J.J Rouseau</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The earliest classification of constitutions was the work of Aristotle. Aristotle was a Greek philosopher who made significant contributions to a variety of fields, including political theory. He classified constitutions into three types: monarchy, aristocracy, and constitutional government.</div>", "topic": "CONSTITUTION"}, {"id": "objective>Government>2011>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Constitutionalism refers to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the process of operating a constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">strict adherence to a constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the process of drafting a constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amendment of an existing constitution</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Constitutionalism refers to strict adherence to a constitution. It is a political philosophy that asserts that governance must be conducted according to an established body of law, which is the constitution. It emphasizes the principle of limited government and the protection of fundamental rights.</div>", "topic": "CONSTITUTION"}, {"id": "objective>Government>2011>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of delegated legislation is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ministers and lawmakers work together</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it hastens the implementation of policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">much time is saved in the process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technical issues are handled by experts</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Delegated legislation refers to laws or regulations passed by an individual or body under powers given to them by primary legislation. It hastens the implementation of policy because it allows the person or body to adapt the law to meet changing needs without needing to wait for a new Act of Parliament to be passed. This is why option 2 is correct.</div>", "topic": "PROCESSES OF LEGISLATION : DELEGATED LEGISLATION"}, {"id": "objective>Government>2011>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One essential duty of citizen to his state is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pay his tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage other citizens to be loyal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">support the government in power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recite the pledge</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the essential duties of a citizen to his state is to pay his taxes. Taxes are a major source of government revenue, which is used to provide public goods and services. Therefore, paying taxes is a fundamental responsibility of every citizen. This is why option 1 is correct.</div>", "topic": "CITIZENSHIP : DUTIES AND OBLIGATIONS OF CITIZENS"}, {"id": "objective>Government>2011>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Franchise in an electoral system means the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sovereignty of power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rights and duties of citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">right to vote</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ownership of the means of production</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Franchise in an electoral system refers to the right to vote. It is the privilege given to citizens to participate in the electoral process by casting their votes. This is a fundamental aspect of democratic societies where citizens have a say in who governs them.</div>", "topic": "THE ELECTORAL PROCESS : SUFFRAGE"}, {"id": "objective>Government>2011>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of party system in practice is defined by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manner in which the parties operate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of political parties in a country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relationship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structure of the political parties</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The type of party system in practice is defined by the number of political parties in a country. This can range from a one-party system, two-party system to a multi-party system. The number of political parties in a country determines the type of party system in place.</div>", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS"}, {"id": "objective>Government>2011>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure groups harmonize different individual concerns through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">interest mobilisation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest aggregation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest formulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structure of the political parties</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure groups harmonize different individual concerns through interest aggregation. Interest aggregation is a political process where political actors express their preferences, and these preferences are combined into a collective decision. Pressure groups play a significant role in this process by bringing together individuals with similar interests and concerns, and representing these collective interests in the political arena.</div>", "topic": "PRESSURE GROUPS"}, {"id": "objective>Government>2011>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Opinion polls are organised to find out the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">people's expectations from government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feelings of people about particular issues and policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">benefits derived by people from government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">people's thought about a particular government policy.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Opinion polls are organised to find out the feelings of people about particular issues and policies. They are a method of collecting public opinion on a variety of topics, including government policies, social issues, and political attitudes. The results of these polls can influence policy decisions and public discourse.</div>", "topic": "PUBLIC OPINION"}, {"id": "objective>Government>2011>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In pre-colonial Igboland, autocratic rule was made difficult by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pressure from age-graders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">activities of cult societies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fear of dethronement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of a centralized system of authority</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In pre-colonial Igboland, autocratic rule was made difficult by the absence of a centralized system of authority. This is because the Igbo society was organized in a way that power was decentralized. Each village or community was autonomous and governed by a council of elders, making it difficult for one person to exercise autocratic rule.</div>", "topic": "PRE-COLONIAL POLITICS : IGBO PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>2011>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Yoruba traditional system of government was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monarchical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">egalitarian</div>", "<div style=\"font-family:Cambria;font-size:17px;\">republican</div>", "<div style=\"font-family:Cambria;font-size:17px;\">democratic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Yoruba traditional system of government was monarchical. This means that it was ruled by a monarch, usually a king or a queen. The monarch was the supreme ruler and had the final say in matters of the state. However, the monarch was assisted by a council of chiefs who advised him and helped in the administration of the kingdom.</div>", "topic": "PRE-COLONIAL POLITICS : YORUBA PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>2011>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the pre-colonial Sokoto Caliphate system, the next in command to the Sultan was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Madaki</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Waziri</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkali</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Galadima</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the pre-colonial Sokoto Caliphate system, the Waziri was the next in command to the Sultan. The Waziri was the chief adviser to the Sultan and was responsible for administrative and judicial functions.</div>", "topic": "PRE-COLONIAL POLITICS : HAUSA PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>2011>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following societies was classified as acephalous</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Igbo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ijaw</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibibio</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Acephalous societies are those that lack political leaders or hierarchies. Such societies are also known as 'egalitarian' or 'non-stratified' societies. The Igbo society is a good example of an acephalous society as they traditionally had a decentralized political system with no centralized authority figures.</div>", "topic": "PRE-COLONIAL POLITICS : OTHER PRE-COLONIAL SYSTEMS IN NIGERIA"}, {"id": "objective>Government>2011>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Indirect rule encouraged </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inter-communal cooperation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rise of nationalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communal integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exploitation and oppression</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Indirect rule was a system of governance used by the British to control parts of their colonial empire, particularly in Africa and Asia, through pre-existing local power structures. These dependencies were often called 'protectorates' or 'trucial states'. This system led to the rise of nationalism as it created a class of Western-educated elites who were excluded from power, leading to demands for more inclusion and ultimately independence.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH COLONIAL ADMINISTRATIVE POLICY – DIRECT AND INDIRECT RULE"}, {"id": "objective>Government>2011>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main achievement of the nationalists in Nigeria was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political liberation of the nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">building the nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">registration of political parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic liberation of the nation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main achievement of the nationalists in Nigeria was the political liberation of the nation. Nationalists fought for and achieved independence from colonial rule. This is considered political liberation as it allowed Nigeria to govern itself independently.</div>", "topic": "PROCESS OF DECOLONIZATION : NATIONALIST MOVEMENTS – EMERGENCE, GOALS, STRATEGIES"}, {"id": "objective>Government>2011>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major external factor that promoted nationalism in Nigeria was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the Second World War</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Anti-apartheid Movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pan-Africanism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Yum Kippur War</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Second World War was a major external factor that promoted nationalism in Nigeria. During the war, many Nigerians were recruited to fight for the British Empire, which led to increased awareness about the world beyond their local communities and the injustices of colonial rule. This awareness sparked a desire for self-rule and independence, thus promoting nationalism.</div>", "topic": "PROCESS OF DECOLONIZATION : INFLUENCE OF EXTERNAL FACTORS"}, {"id": "objective>Government>2011>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presidential system of government was introduced in Nigeria with the Constitution of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1960</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1979</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1989</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1999</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presidential system of government was introduced in Nigeria with the Constitution of 1979. Prior to this, Nigeria operated a parliamentary system of government. The 1979 Constitution marked a shift from the parliamentary system to a presidential system, where the President is both the head of state and the head of government.</div>", "topic": "SYSTEMS OF GOVERNANCE : PRESIDENTIAL SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>2011>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Action Group crises of 1963 led to the formation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NPC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NCNC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">UPP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NEPU</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Action Group crises of 1963 led to the formation of the United Progressive Party (UPP). The Action Group (AG) was a political party in Nigeria that was prominent in the Western region of the country. In 1963, there was a crisis within the party that led to a split, and the formation of the UPP.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : 1963 CONSTITUTION"}, {"id": "objective>Government>2011>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1963 Republican Constitution, the power of judicial review was vested in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Supreme Court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Parliament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">President</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chief Justice</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1963 Republican Constitution, the power of judicial review was vested in the Supreme Court. Judicial review is the power of a court to review the actions of public sector bodies in terms of their legality, or to review the constitutionality of legislation or some types of executive actions. In Nigeria, this power is vested in the Supreme Court, which is the highest court in the land.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>2011>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rules and regulations of the civil service are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Service order</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Administrative Order</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General Order</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bureaucratic Order</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rules and regulations of the civil service are referred to as the 'General Order'. This is a document that contains all the rules, regulations, and procedures that guide the conduct and operation of the civil service. It is designed to ensure that civil servants carry out their duties efficiently and effectively, and in a manner that is fair, transparent, and accountable.</div>", "topic": "THE CIVIL SERVICE"}, {"id": "objective>Government>2011>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Code of Conduct Bureau was essentially established to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enhance probity and accountability in public service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure the independence of the public service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce corruption in public life</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the rights of public servants</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Code of Conduct Bureau was essentially established to 'enhance probity and accountability in public service'. The Bureau is responsible for establishing and maintaining a high standard of morality in the conduct of government business and to ensure that the actions and behavior of public officers conform to the highest standards of public morality and accountability.</div>", "topic": "ETHICS AND ACCOUNTABILITY IN PUBLIC OFFICE"}, {"id": "objective>Government>2011>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following political parties was the first to be formed when the ban on politics was lifted in 1978?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NPN</div>", "<div style=\"font-family:Cambria;font-size:17px;\">UPN</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NPP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PRP</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">UPN was the first to be formed when the ban on politics was lifted in 1978. On September 31, 1978, General Obasanjo lifted ban partisan politics.</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : FOURTH REPUBLIC"}, {"id": "objective>Government>2011>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of federal character was adopted in order to promote equitable allocation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">opportunities between males and females</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenue between groups in the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positions and appointments among people of various regions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appointments between the North and the South</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of federal character was adopted in Nigeria to promote equitable allocation of positions and appointments among people of various regions. This principle is enshrined in the 1999 Constitution of the Federal Republic of Nigeria to ensure that appointments to public service institutions fairly reflect the linguistic, ethnic, religious, and geographic diversity of the country. It is designed to prevent the predominance of a few ethnic groups or regions in the administration of the federal government.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : PROBLEMS OF NIGERIAN FEDERALISM – CENSUS, REVENUE ALLOCATION, CONFLICTS ETC"}, {"id": "objective>Government>2011>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The component units of the Nigerian federation comprise</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">federal, state, local government and federal capital territory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">federal capital territory,national assembly,supreme court and civil service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">national assembly, military, police and civil service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constituency, ward, emirate and chiefdom</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian federation is made up of the federal government, the 36 states, 774 local government areas, and the Federal Capital Territory (FCT). The federal government is the central government, while the states and local governments are the sub-units. The Federal Capital Territory is also a component unit of the federation, serving as the nation's capital.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM"}, {"id": "objective>Government>2011>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, privatization and commercialization policies were introduced to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">divest government major control of commercial ventures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allow government control of the private sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hand over the control of commercial ventures to citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the asset base of government</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization and commercialization policies were introduced in Nigeria to reduce the involvement of the government in commercial ventures and to promote private sector participation. Privatization involves the transfer of ownership of government property to the private sector. Commercialization, on the other hand, involves the reorganization of enterprises wholly or partly owned by the government in which such commercialized enterprises are expected to operate profitably as private enterprises. The main aim is to divest government major control of commercial ventures.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS"}, {"id": "objective>Government>2011>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a public corporation in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">National Population Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">First Bank of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Universities Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Television Authority</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A public corporation is a company that is owned by the government, and its purpose is to provide a public service. The Nigerian Television Authority (NTA) is an example of a public corporation in Nigeria because it is owned by the government of Nigeria and provides television broadcasting services to the public.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS"}, {"id": "objective>Government>2011>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Following the reform of the Native Authority system in Northern Nigeria, traditional rulers became</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prefects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chief-in-council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chief-and-council</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Following the reform of the Native Authority system in Northern Nigeria, traditional rulers became Chief-in-council. This means that they were still the traditional rulers, but they now had a council of advisors. This was done to decentralize power and make the governance system more democratic.</div>", "topic": "LOCAL GOVERNMENT"}, {"id": "objective>Government>2011>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under whose regime were Akwa Ibom and and Katsina States created?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">General Sani Abacha</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General Yakubu Gowon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General Murtala Muhammed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General Ibrahim Babangida</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Akwa Ibom and Katsina States were created during the regime of General Ibrahim Babangida. He was the military president of Nigeria from 1985 to 1993 and during his regime, he created several states including Akwa Ibom and Katsina in 1987 and 1991 respectively.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : JOHN MACPHERSON CONSTITUTION 1951"}, {"id": "objective>Government>2011>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1999 Constitution of the Federal Republic of Nigeria, the appointment and posting of members of election tribunal on the elections conducted by INEC is the responsibility of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chief Justice of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">President, Court of Appeal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chairman, Independent National Electoral Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">President of Nigeria</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1999 Constitution of the Federal Republic of Nigeria, the appointment and posting of members of election tribunal on the elections conducted by INEC is the responsibility of the President, Court of Appeal. The Constitution provides that the President of the Court of Appeal shall appoint the Chairman and other members of the election tribunal from among the Judges of the Court of Appeal, the High Court of a State, and the High Court of the Federal Capital Territory, Abuja.</div>", "topic": "INSTITUTIONS OF GOVERNMENT IN THE POST-INDEPENDENCE NIGERIA : THE JUDICIARY – STRUCTURE, FUNCTIONS AND WORKINGS."}, {"id": "objective>Government>2011>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rhodesia was the former name of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zambia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Namibia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zimbabwe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Swaziland</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rhodesia was the former name of Zimbabwe. The country was known as Rhodesia during the period of British colonial rule, which ended in 1980. The name was changed to Zimbabwe after gaining independence.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH PROCESS OF ACQUISITION – TRADE, MISSIONARY ACTIVITIES, COMPANY RULE, CROWN COLONY, PROTECTORATE"}, {"id": "objective>Government>2011>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The adoption of non-alignment as a principle of Nigeria's foreign policy was aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fulfilling a basic requirement for acceptance in the UN Security Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insulating Nigeria against having to take side in the Cold War</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promoting Nigeria's leadership aspiration in Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attaining equal status with the world powers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The adoption of non-alignment as a principle of Nigeria's foreign policy was aimed at insulating Nigeria against having to take side in the Cold War. Non-alignment is a policy of not aligning with any major power blocs. During the Cold War, many newly independent nations adopted this policy to avoid being drawn into the conflict between the United States and the Soviet Union.</div>", "topic": "NIGERIA’S FOREIGN POLICY : NIGERIA’S NON-ALIGNMENT POLICY"}, {"id": "objective>Government>2011>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In 1979, the non-aligned member states were</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">19</div>", "<div style=\"font-family:Cambria;font-size:17px;\">21</div>", "<div style=\"font-family:Cambria;font-size:17px;\">27</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In 1979, the non-aligned member states were 27. The Non-Aligned Movement (NAM) is a group of states considering themselves not aligned formally with or against any major power bloc. The purpose of the organization as stated in the Havana Declaration of 1979 is to ensure 'the national independence, sovereignty, territorial integrity and security of non-aligned countries'.</div>", "topic": "NIGERIA’S FOREIGN POLICY : NIGERIA’S NON-ALIGNMENT POLICY"}, {"id": "objective>Government>2011>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following was a Secretary General of OPEC?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dalhatu Bayero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rilwan Lukman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jibril Aminu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aret Adams</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rilwan Lukman was a Secretary General of OPEC. The Organization of the Petroleum Exporting Countries (OPEC) is an intergovernmental organization of 13 nations. The Secretary General is the legally authorized representative of the Organization and Chief Executive of the Secretariat.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OPEC"}, {"id": "objective>Government>2011>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following countries pioneered the idea of ECOWAS alongside Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cote d'Ivoire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mali</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liberia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Togo</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Economic Community of West African States (ECOWAS) was established on May 28, 1975, via the Treaty of Lagos, in Lagos, Nigeria. The founding members were Nigeria, Niger, Senegal, Sierra Leone, Togo, Upper Volta (now Burkina Faso), and Cote d'Ivoire. Therefore, Cote d'Ivoire is the correct answer.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS"}, {"id": "objective>Government>2011>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following international organisations was in existence before the Second World War?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The League of Nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The ECOWAS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The UNO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The OAU</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The League of Nations was an international diplomatic group developed after World War I as a way to solve disputes between countries before they erupted into open warfare. It was established on 10 January 1920 following the Paris Peace Conference that ended the First World War. It was the first international organization whose principal mission was to maintain world peace. The other options like ECOWAS, UNO, and OAU were established after the Second World War.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>2011>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organ of the United Nations responsible for the approval of its annual budget is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">General Assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economic and Social Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Secretariat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Security Council</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The General Assembly is the main deliberative, policymaking and representative organ of the UN. All 193 Member States of the UN are represented in the General Assembly, making it the only UN body with universal representation. Each year, in September, the full UN membership meets in the General Assembly Hall in New York for the annual General Assembly session, and general debate, which many heads of state attend and address. Decisions on important questions, such as those on peace and security, admission of new members and budgetary matters, require a two-thirds majority of the General Assembly. Decisions on other questions are by simple majority.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>2011>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Each member state is represented on the Board of Governors of OPEC for a period of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 years</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Each member state of OPEC is represented on the Board of Governors for two years.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OPEC"}];
